import React, { useState } from "react";
import { fn, userEvent, within, expect } from "@storybook/test";

import { Button } from "../Button";
import { Drawer } from "./Drawer";
import { Input } from "../Input";
import { Stack } from "../Stack";
import { Text } from "../Text";

export default {
  title: "Overlay/Drawer",
  component: Drawer,
  tags: ["autodocs"],
  parameters: {
    layout: "padded",
    docs: {
      description: {
        component:
          "Drawer component for displaying content in a sliding panel from the edge of the screen.",
      },
    },
  },
  args: {
    onOpenChange: fn(),
    onExitComplete: fn(),
  },
  argTypes: {
    size: {
      control: "select",
      options: ["xs", "sm", "md", "lg", "xl", "full"],
      description: "Size of the drawer",
    },
    placement: {
      control: "select",
      options: ["top", "bottom", "start", "end"],
      description: "Placement of the drawer",
    },
    onOpenChange: {
      action: "open changed",
      description: "Callback when drawer open state changes",
    },
    onExitComplete: {
      action: "exit complete",
      description: "Callback when drawer exit animation completes",
    },
  },
};

export const Default = {
  args: {
    size: "md",
    placement: "end",
  },
  render: (args) => (
    <Drawer {...args}>
      <Drawer.Trigger>
        <Button>Open Drawer</Button>
      </Drawer.Trigger>
      <Drawer.Content>
        <Drawer.Header>
          <Drawer.Title>Drawer Title</Drawer.Title>
        </Drawer.Header>
        <Drawer.Body>
          <Text>
            This is the drawer content. Drawers are typically used for navigation, forms, or
            displaying additional information.
          </Text>
        </Drawer.Body>
        <Drawer.Footer>
          <Drawer.ActionTrigger>
            <Button variant="outline">Cancel</Button>
          </Drawer.ActionTrigger>
          <Button>Save</Button>
        </Drawer.Footer>
        <Drawer.CloseTrigger />
      </Drawer.Content>
    </Drawer>
  ),
  play: async ({ canvasElement, args }) => {
    const canvas = within(canvasElement);
    const openButton = canvas.getByRole("button", { name: /open drawer/i });

    // Click to open drawer
    await userEvent.click(openButton);
    await expect(args.onOpenChange).toHaveBeenCalled();
  },
};

export const Placements = {
  args: {},
  render: (args) => (
    <Stack direction="row" gap={4} wrap="wrap">
      {["start", "end", "top", "bottom"].map((placement) => (
        <Drawer key={placement} placement={placement} {...args}>
          <Drawer.Trigger>
            <Button variant="outline">{placement}</Button>
          </Drawer.Trigger>
          <Drawer.Content>
            <Drawer.Header>
              <Drawer.Title>Placement: {placement}</Drawer.Title>
            </Drawer.Header>
            <Drawer.Body>
              <Text>Drawer from the {placement}.</Text>
            </Drawer.Body>
            <Drawer.CloseTrigger />
          </Drawer.Content>
        </Drawer>
      ))}
    </Stack>
  ),
};

